#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>

#define PORT 8080
#define BACKLOG 5
#define BUFSIZE 1024

int main(void) {
    int sockfd, connfd;
    struct sockaddr_in serv_addr, cli_addr;
    socklen_t cli_len = sizeof(cli_addr);
    char buf[BUFSIZE];

    /* 1. Create socket */
    sockfd = socket(AF_INET, SOCK_STREAM, 0);
    if (sockfd == -1) { perror("socket"); exit(1); }

    /* 2. Allow address reuse */
    int opt = 1;
    setsockopt(sockfd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    /* 3. Bind to port */
    memset(&serv_addr, 0, sizeof(serv_addr));
    serv_addr.sin_family = AF_INET;
    serv_addr.sin_addr.s_addr = htonl(INADDR_ANY);
    serv_addr.sin_port = htons(PORT);

    if (bind(sockfd, (struct sockaddr *)&serv_addr, sizeof(serv_addr)) == -1) {
        perror("bind"); close(sockfd); exit(1);
    }

    /* 4. Listen */
    if (listen(sockfd, BACKLOG) == -1) {
        perror("listen"); close(sockfd); exit(1);
    }
    printf("Server listening on port %d\n", PORT);

    /* 5. Accept and handle one client */
    connfd = accept(sockfd, (struct sockaddr *)&cli_addr, &cli_len);
    if (connfd == -1) { perror("accept"); close(sockfd); exit(1); }

    ssize_t n = read(connfd, buf, BUFSIZE - 1);
    if (n > 0) {
        buf[n] = '\0';
        printf("Received: %s\n", buf);
        write(connfd, "Hello from server\n", 18);
    }

    close(connfd);
    close(sockfd);
    return 0;
}

