void demonstrate_send_recv(int sockfd) {
    const char *msg = "Hello, network!";

    /* send with flags=0 is the same as write */
    send(sockfd, msg, strlen(msg), 0);
    /* equivalent: write(sockfd, msg, strlen(msg)); */

    char buf[1024];

    /* recv with MSG_WAITALL: block until we get exactly 15 bytes */
    ssize_t n = recv(sockfd, buf, 15, MSG_WAITALL);

    /* recv with MSG_PEEK: look at data without consuming it */
    n = recv(sockfd, buf, sizeof(buf), MSG_PEEK);
    /* data is still in the buffer -- next recv/read returns it again */

    /* On Linux: avoid SIGPIPE on broken connections */
    #ifdef MSG_NOSIGNAL
    send(sockfd, msg, strlen(msg), MSG_NOSIGNAL);
    #endif

    /* MSG_DONTWAIT: non-blocking for just this call */
    n = recv(sockfd, buf, sizeof(buf), MSG_DONTWAIT);
    /* returns -1 with errno=EAGAIN if no data available */
}

