    addr.sin_family = AF_INET;
    addr.sin_addr.s_addr = htonl(INADDR_ANY);
    addr.sin_port = htons(8080);

    /* This bind succeeds even if port 8080 is in TIME_WAIT */
    if (bind(sockfd, (struct sockaddr *)&addr, sizeof(addr)) == -1) {
        perror("bind");
        close(sockfd);
        exit(1);
    }

    printf("Bound successfully with SO_REUSEADDR\n");

    /* Check current value */
    int val;
    socklen_t len = sizeof(val);
    getsockopt(sockfd, SOL_SOCKET, SO_REUSEADDR, &val, &len);
