void sigchld_handler(int sig) {
    (void)sig;
    /* Reap all dead children (non-blocking) */
    while (waitpid(-1, NULL, WNOHANG) > 0)
        ;
}

void handle_client(int connfd) {
    char buf[BUFSIZE];
    ssize_t n;
    while ((n = read(connfd, buf, BUFSIZE - 1)) > 0) {
        buf[n] = '\0';
        write(connfd, buf, n); /* echo back */
    }
}

int main(void) {
    /* Install SIGCHLD handler to prevent zombies */
    struct sigaction sa;
    sa.sa_handler = sigchld_handler;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = SA_RESTART; /* restart accept() after signal */
    sigaction(SIGCHLD, &sa, NULL);

    int sockfd = socket(AF_INET, SOCK_STREAM, 0);
    int opt = 1;
    setsockopt(sockfd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    struct sockaddr_in addr = {0};
    addr.sin_family = AF_INET;
    addr.sin_addr.s_addr = htonl(INADDR_ANY);
    addr.sin_port = htons(PORT);
    bind(sockfd, (struct sockaddr *)&addr, sizeof(addr));
    listen(sockfd, 128);

    printf("Concurrent server on port %d\n", PORT);

    for (;;) {
        int connfd = accept(sockfd, NULL, NULL);
        if (connfd == -1) continue; /* interrupted by signal */

        pid_t pid = fork();
        if (pid == 0) {
            /* Child */
            close(sockfd);
            handle_client(connfd);
            close(connfd);
            exit(0);
        } else if (pid > 0) {
            /* Parent */
            close(connfd); /* parent doesn't need client fd */
        } else {
            perror("fork");
            close(connfd);
        }
    }
}

