#define PORT 8080
#define MAX_CLIENTS 10
#define BUFSIZE 1024

int main(void) {
    int listenfd = socket(AF_INET, SOCK_STREAM, 0);
    int opt = 1;
    setsockopt(listenfd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    struct sockaddr_in addr = {0};
    addr.sin_family = AF_INET;
    addr.sin_addr.s_addr = htonl(INADDR_ANY);
    addr.sin_port = htons(PORT);
    bind(listenfd, (struct sockaddr *)&addr, sizeof(addr));
    listen(listenfd, 5);

    int clients[MAX_CLIENTS];
    int ncli = 0;

    for (;;) {
        fd_set readfds;
        FD_ZERO(&readfds);
        FD_SET(listenfd, &readfds);
        int maxfd = listenfd;

        for (int i = 0; i < ncli; i++) {
            FD_SET(clients[i], &readfds);
            if (clients[i] > maxfd) maxfd = clients[i];
        }

        int ready = select(maxfd + 1, &readfds, NULL, NULL, NULL);
        if (ready == -1) { perror("select"); break; }

        /* New connection? */
        if (FD_ISSET(listenfd, &readfds)) {
            int connfd = accept(listenfd, NULL, NULL);
            if (connfd >= 0 && ncli < MAX_CLIENTS) {
                clients[ncli++] = connfd;
                printf("New client (fd=%d)\n", connfd);
            }
        }

        /* Data from existing clients? */
        for (int i = 0; i < ncli; i++) {
            if (FD_ISSET(clients[i], &readfds)) {
                char buf[BUFSIZE];
                ssize_t n = read(clients[i], buf, BUFSIZE - 1);
                if (n <= 0) {
                    close(clients[i]);
                    clients[i] = clients[--ncli]; /* remove */
                    i--;
                } else {
                    buf[n] = '\0';
                    write(clients[i], buf, n); /* echo */
                }
            }
        }
    }
    close(listenfd);
    return 0;
}

