/* Make a socket non-blocking */
int set_nonblocking(int fd) {
    int flags = fcntl(fd, F_GETFL, 0);
    if (flags == -1) return -1;
    return fcntl(fd, F_SETFL, flags | O_NONBLOCK);
}

void non_blocking_read_example(int sockfd) {
    char buf[1024];

    set_nonblocking(sockfd);

    for (;;) {
        ssize_t n = read(sockfd, buf, sizeof(buf) - 1);
        if (n > 0) {
            buf[n] = '\0';
            printf("Got: %s\n", buf);
        } else if (n == 0) {
            printf("Connection closed\n");
            break;
        } else { /* n == -1 */
            if (errno == EAGAIN || errno == EWOULDBLOCK) {
                /* No data available right now -- do other work */
                printf("Would block, try later\n");
                break; /* or use select/poll to wait */
            } else {
                perror("read");
                break;
            }
        }
    }
}

/* Non-blocking connect */
int nonblocking_connect(const char *ip, int port) {
    int fd = socket(AF_INET, SOCK_STREAM, 0);
    set_nonblocking(fd);

    struct sockaddr_in addr = {0};
    addr.sin_family = AF_INET;
    addr.sin_port = htons(port);
    inet_pton(AF_INET, ip, &addr.sin_addr);

    int ret = connect(fd, (struct sockaddr *)&addr, sizeof(addr));
    if (ret == -1 && errno == EINPROGRESS) {
        /* Connection in progress -- use select/poll to wait */
        fd_set wfds;
        FD_ZERO(&wfds);
        FD_SET(fd, &wfds);
        struct timeval tv = {5, 0}; /* 5 second timeout */
        select(fd + 1, NULL, &wfds, NULL, &tv);

        int err;
        socklen_t len = sizeof(err);
        getsockopt(fd, SOL_SOCKET, SO_ERROR, &err, &len);
        if (err != 0) {
            fprintf(stderr, "Connect failed: %s\n", strerror(err));
            close(fd);
            return -1;
        }
    }
    return fd;
}

