        "\r\n", path, host);

    write(sockfd, request, reqlen);

    /* Read response */
    char buf[BUFSIZE];
    ssize_t n;
    while ((n = read(sockfd, buf, BUFSIZE - 1)) > 0) {
        buf[n] = '\0';
        printf("%s", buf);
    }

    close(sockfd);
    return 0;
