/* Common interview question: message framing for TCP */
/* Since TCP is a byte stream, you need a protocol to
   delimit messages. Common approaches: */
/* 1. Length prefix: send 4-byte length, then data */
/* 2. Delimiter: use \n or \0 to mark end of message */
/* 3. Fixed-size messages */

/* Length-prefixed send */
int send_message(int fd, const char *msg, size_t len) {
    uint32_t net_len = htonl((uint32_t)len);
    write(fd, &net_len, sizeof(net_len));  /* send length */
    write(fd, msg, len);                    /* send data */
    return 0;
}

/* Length-prefixed receive */
int recv_message(int fd, char *buf, size_t bufsize) {
    uint32_t net_len;
    read(fd, &net_len, sizeof(net_len));   /* read length */
    uint32_t msg_len = ntohl(net_len);
    if (msg_len > bufsize) return -1;
    read(fd, buf, msg_len);                /* read data */
    return (int)msg_len;
}

